#include <bits/stdc++.h>
using namespace std;
const int N = 100 * 1001;
int mx, cnt[2], leaves[N];
vector<int> g[N];
void dfs(int v, int e, int par) {
  for (int i = 0; i < g[v].size(); i++)
    if (g[v][i] != par) dfs(g[v][i], e + 1, v);
  if (g[v].size() != 1) return;
  cnt[e % 2]++;
  if (leaves[par]++) mx--;
}
int main() {
  int n;
  cin >> n;
  mx = n - 1;
  for (int i = 0; i < n - 1; i++) {
    int a, b;
    cin >> a >> b;
    g[a].push_back(b);
    g[b].push_back(a);
  }
  int v = 1;
  while (g[v].size() == 1) v++;
  dfs(v, 0, 0);
  cout << (cnt[1] && cnt[0] ? 3 : 1) << ' ' << mx << '\n';
}
